class ETGBNIcheckPrintController extends SrsReportRunController
{
    LedgerJournalTrans             ledgerJournalTrans;

}

Method.Source:
protected void prePromptModifyContract()
{
    ETGUBACheckPrintContract         LedgerJournal;

    ledgerJournalTrans =    this.parmArgs().record();
    LedgerJournal   = this.parmReportContract().parmRdpContract() as ETGUBACheckPrintContract;      
    LedgerJournal.parmRecid(ledgerJournalTrans.RecId);
}

public static ETGBNIcheckPrintController construct()
{
    return new ETGBNIcheckPrintController();
}

public static void main(Args _args)
{
    ETGBNIcheckPrintController LedgerJournal  = new ETGBNIcheckPrintController();
    LedgerJournal.parmArgs(_args);
    LedgerJournal.parmReportName(ssrsReportStr(ETGUBACheckPrint, ETGBNICheckPrint));
    LedgerJournal.parmShowDialog(false);
    LedgerJournal.startOperation();
}
